import React, { useState } from 'react';

export const Navbar = ({ user, onLogout }) => {
  const [menuOpen, setMenuOpen] = useState(false);

  const navigate = (path) => {
    const parts = path.split('/').filter(p => p);
    window.location.hash = path;
  };

  return (
    <header>
      <nav>
        <div className="logo" onClick={() => navigate('/')} style={{ cursor: 'pointer' }}>💼 FreelanceHub</div>
        <ul>
          <li><a href="#/" onClick={() => navigate('/')}>Browse Projects</a></li>
          <li><a href="#/freelancers" onClick={() => navigate('/freelancers')}>Find Freelancers</a></li>
          {user ? (
            <>
              <li><a href="#/dashboard" onClick={() => navigate('/dashboard')}>Dashboard</a></li>
              <li><a href="#/messages" onClick={() => navigate('/messages')}>Messages</a></li>
              <li><a href="#/profile" onClick={() => navigate('/profile')}>Profile</a></li>
              <li><button className="btn btn-secondary" onClick={onLogout}>Logout</button></li>
            </>
          ) : (
            <>
              <li><a href="#/login" onClick={() => navigate('/login')} className="btn btn-primary">Login</a></li>
              <li><a href="#/register" onClick={() => navigate('/register')} className="btn btn-secondary">Sign Up</a></li>
            </>
          )}
        </ul>
      </nav>
    </header>
  );
};

export const Footer = () => {
  return (
    <footer style={{
      background: '#333',
      color: 'white',
      padding: '40px 20px',
      textAlign: 'center',
      marginTop: '60px'
    }}>
      <div className="container">
        <p>&copy; 2024 FreelanceHub. All rights reserved.</p>
        <div style={{ marginTop: '20px' }}>
          <a href="#" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Privacy</a>
          <a href="#" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Terms</a>
          <a href="#" style={{ color: 'white', margin: '0 10px', textDecoration: 'none' }}>Contact</a>
        </div>
      </div>
    </footer>
  );
};
